class Solution {
public:
    int maximumLengthSubstring(string s) {
        int left = 0, maxLen = 0;
        unordered_map<char, int> count;
        for (int right = 0; right < s.size(); right++) {
            count[s[right]]++;
            while (count[s[right]] > 2) {
                count[s[left]]--;
                if (count[s[left]] == 0) {
                    count.erase(s[left]);
                }
                left++;
            }
            maxLen = max(maxLen, right - left + 1);
        }
        return maxLen;
    }
};

